const summary = $('Get Daily Summary').first().json;
const accuracy = $('Get Today Accuracy').first().json;
const chartUrl = 'https://btc-oracle-production.up.railway.app/api/charts/accuracy.png?days=1&size=twitter';

const prompt = `Write an evening results tweet comparing what BTC Seer predicted vs what happened today. Here's the data:

Daily Summary: ${JSON.stringify(summary, null, 2)}

Today's Accuracy: ${JSON.stringify(accuracy, null, 2)}

An accuracy chart image is available at: ${chartUrl}
Include this URL at the end of your tweet so it shows as a preview image.

Be transparent about misses — our credibility comes from honesty. Max 270 chars (not counting the URL). Include #Bitcoin #BTC. End with CTA to @BTC_Seer_Bot.`;

return [{ json: { prompt, chartUrl } }];

const response = $('Claude Generate').first().json;
const text = response.content[0].text.trim();
return [{ json: { text } }];

const tweet = $('Extract Tweet Text').first().json.text;
const now = new Date().toISOString();
console.log(`[${now}] Evening results tweet posted: ${tweet.substring(0, 80)}...`);
return [{ json: { status: 'posted', timestamp: now, tweet_length: tweet.length } }];
